import{_ as t,o,c as r,a2 as i}from"./chunks/framework.BWuWLRhz.js";const s="/assets/clash-mi-01.CKaUGLI1.png",e="/assets/clash-mi-02.C3Mc8xb1.png",l="/assets/clash-mi-03.B8zsqC06.png",n="/assets/clash-mi-04.CjwSFdlP.png",p="/assets/clash-mi-05.By1Lmbj_.png",b=JSON.parse('{"title":"Clash Mi for iOS / iPadOS","description":"iOS / iPadOS 推荐客户端 Clash Mi 图文配置教程，免费、导入快、五步完成连接。","frontmatter":{"description":"iOS / iPadOS 推荐客户端 Clash Mi 图文配置教程，免费、导入快、五步完成连接。"},"headers":[],"relativePath":"clients/ios/clash-mi.md","filePath":"clients/ios/clash-mi.md","lastUpdated":1783292109000}'),h={name:"clients/ios/clash-mi.md"};function c(d,a,g,m,u,f){return o(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="clash-mi-for-ios-ipados" tabindex="-1">Clash Mi for iOS / iPadOS <a class="header-anchor" href="#clash-mi-for-ios-ipados" aria-label="Permalink to &quot;Clash Mi for iOS / iPadOS&quot;">​</a></h1><blockquote><p><strong>iOS / iPadOS 首选推荐 · 免费</strong> | 订阅导入简单，日常使用稳定</p></blockquote><p>Clash Mi 适合自由港机场用户在 iPhone / iPad 上快速完成订阅导入和节点切换，操作路径清晰，适合新手和日常使用。</p><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><ul><li>iOS / iPadOS 15 及以上（建议使用最新系统）</li><li>可正常访问 App Store</li><li>设备可创建 VPN 配置</li></ul><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><ul><li>App Store 直达链接：<a href="https://apps.apple.com/app/id6744321968" target="_blank" rel="noreferrer">前往下载</a></li><li>使用外区 Apple ID 在 App Store 搜索并安装 <code>Clash Mi</code></li><li>建议安装后先升级到最新版本再导入订阅</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>此类应用在国区 App Store 未上架，需要美区等外区 Apple ID 下载。登录外区 ID 下载后可切回常用账号，应用保留可用。</p></div><h2 id="配置教程" tabindex="-1">配置教程 <a class="header-anchor" href="#配置教程" aria-label="Permalink to &quot;配置教程&quot;">​</a></h2><h3 id="步骤一-复制订阅链接" tabindex="-1">步骤一：复制订阅链接 <a class="header-anchor" href="#步骤一-复制订阅链接" aria-label="Permalink to &quot;步骤一：复制订阅链接&quot;">​</a></h3><p>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">自由港机场会员中心</a>，在「我的订阅」的订阅链接区域，点击右侧的<strong>复制</strong>按钮复制订阅链接；也可以直接点击 <strong>Clash Mi</strong> 下方的<strong>一键导入</strong>尝试自动唤起应用。</p><p><img src="'+s+'" alt="在会员中心复制订阅链接或一键导入"></p><h3 id="步骤二-新建配置" tabindex="-1">步骤二：新建配置 <a class="header-anchor" href="#步骤二-新建配置" aria-label="Permalink to &quot;步骤二：新建配置&quot;">​</a></h3><p>打开 Clash Mi，在主界面的「我的配置」一栏，点击右侧的<strong>加号（+）</strong>。</p><p><img src="'+e+'" alt="点击我的配置加号"></p><h3 id="步骤三-选择添加配置链接" tabindex="-1">步骤三：选择添加配置链接 <a class="header-anchor" href="#步骤三-选择添加配置链接" aria-label="Permalink to &quot;步骤三：选择添加配置链接&quot;">​</a></h3><p>在底部弹出的菜单中，选择<strong>添加配置链接</strong>。</p><p><img src="'+l+'" alt="选择添加配置链接"></p><h3 id="步骤四-填写配置并保存" tabindex="-1">步骤四：填写配置并保存 <a class="header-anchor" href="#步骤四-填写配置并保存" aria-label="Permalink to &quot;步骤四：填写配置并保存&quot;">​</a></h3><p>在「添加配置链接」页面：</p><ol><li>在<strong>配置链接 / 内容</strong>框中粘贴步骤一复制的订阅链接</li><li>在<strong>备注</strong>框填写一个名称，例如 <code>freedomport</code></li><li>完成后点击右上角的**对勾（√）**保存</li></ol><p><img src="'+n+'" alt="填写订阅链接和备注并保存"></p><p>保存后应用会自动拉取节点配置，稍等片刻即可完成导入。</p><h3 id="步骤五-连接节点" tabindex="-1">步骤五：连接节点 <a class="header-anchor" href="#步骤五-连接节点" aria-label="Permalink to &quot;步骤五：连接节点&quot;">​</a></h3><p>回到主界面，点击右上角的<strong>连接开关</strong>，首次连接时允许系统的 VPN 请求，开关变绿即表示已连接。</p><ul><li>保持默认的<strong>规则</strong>模式即可自动分流</li><li>点击<strong>代理</strong>一栏可以查看当前节点、手动切换到延迟更低的节点</li></ul><p><img src="'+p+'" alt="点击连接开关开始连接"></p><p>连接成功后，打开浏览器访问外网验证是否正常。</p><h2 id="推荐设置" tabindex="-1">推荐设置 <a class="header-anchor" href="#推荐设置" aria-label="Permalink to &quot;推荐设置&quot;">​</a></h2><ul><li><strong>连接模式</strong>：默认使用规则模式（Rule），不建议长期全局代理，除非有明确需求</li><li><strong>订阅更新</strong>：购买新套餐或续费后，进入配置列表手动更新一次；也可依赖添加配置时设置的自动更新间隔</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 提示订阅无效？</strong> A: 检查链接是否完整；用浏览器打开链接测试是否有返回内容。</p><p><strong>Q: 显示已连接但无法上网？</strong> A: 切换节点测试；关闭再重新开启连接开关；检查系统时间与时区是否准确。</p><p><strong>Q: 节点全部不可用？</strong> A: 更新订阅后重测；确认套餐在有效期内、流量未用完。</p><p>更多问题见<a href="./../../guide/faq">常见问题 FAQ</a>，或通过<a href="./../../support">联系支持</a>获取帮助。</p><hr><blockquote><p>最后更新：2026 年 3 月 28 日 · 适用平台 iOS / iPadOS</p></blockquote>',37)])])}const q=t(h,[["render",c]]);export{b as __pageData,q as default};
